async (params, browser) => {
  // Open Google Calendar
  await browser.open('https://calendar.google.com/calendar/r')

  // Wait for calendar to load
  await browser.waitForSelector('[role=\'main\'], [data-eventid], .FAxxKc', 20000)

  // Let calendar fully render
  await browser.wait(2000)

  // Open search
  const open_search = await browser.evaluate(`const searchBtn = document.querySelector('[aria-label="Search"], #sb_cb50, button[data-tooltip="Search"]'); if (searchBtn) { searchBtn.click(); await new Promise(r => setTimeout(r, 1500)); } return { search_opened: !!searchBtn }`)

  // Search for the event by title
  const search_event = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search"], input[aria-label="Search for people, events"], input#sb_cb50, input[type="search"]'); if (!searchInput) return { error: 'Could not find search input' }; searchInput.focus(); const nativeSet = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeSet.call(searchInput, params.event_title); searchInput.dispatchEvent(new Event('input', { bubbles: true })); searchInput.dispatchEvent(new Event('change', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); await new Promise(r => setTimeout(r, 3000)); return { searched: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Click on the matching event
  const click_event = await browser.evaluate(`const query = params.event_title.toLowerCase(); const eventElements = document.querySelectorAll('[data-eventid], [data-eventchip], .FAxxKc, [data-searchresultid]'); let target = null; eventElements.forEach(el => { if (target) return; const text = (el.getAttribute('aria-label') || el.textContent || '').toLowerCase(); if (text.includes(query)) target = el; }); if (!target) return { error: 'Event not found: ' + params.event_title + '' }; target.click(); await new Promise(r => setTimeout(r, 2000)); return { event_clicked: true }`)

  // Click edit button on event detail popup
  const open_edit = await browser.evaluate(`const editBtn = document.querySelector('[aria-label="Edit event"], [data-tooltip="Edit event"], button[aria-label*="Edit"], .pencil-button, [jsname="ViaHrd"]'); if (editBtn) { editBtn.click(); await new Promise(r => setTimeout(r, 2500)); return { edit_opened: true }; } const detailLink = document.querySelector('a[href*="/eventedit/"], a[aria-label*="Edit"]'); if (detailLink) { detailLink.click(); await new Promise(r => setTimeout(r, 2500)); return { edit_opened: true }; } return { error: 'Could not find edit button' }`)

  // Let edit form load
  await browser.wait(2000)

  // Modify event fields
  const modify_fields = await browser.evaluate(`const newTitle = params.new_title; const newDate = params.new_date; const newTime = params.new_time; const nativeSet = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; const changes = []; if (newTitle) { const titleInput = document.querySelector('input[aria-label="Title"], [data-key="title"] input, input[placeholder="Add title"], input[aria-label="Add title"]'); if (titleInput) { titleInput.focus(); titleInput.select(); await new Promise(r => setTimeout(r, 300)); nativeSet.call(titleInput, newTitle); titleInput.dispatchEvent(new Event('input', { bubbles: true })); titleInput.dispatchEvent(new Event('change', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); changes.push('title'); } } if (newDate) { const dateInput = document.querySelector('input[aria-label*="date" i], input[aria-label*="Start date" i]'); if (dateInput) { const [y, m, d] = newDate.split('-'); const dateObj = new Date(parseInt(y), parseInt(m) - 1, parseInt(d)); const formatted = dateObj.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }); dateInput.focus(); dateInput.click(); await new Promise(r => setTimeout(r, 300)); nativeSet.call(dateInput, formatted); dateInput.dispatchEvent(new Event('input', { bubbles: true })); dateInput.dispatchEvent(new Event('change', { bubbles: true })); dateInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, bubbles: true })); await new Promise(r => setTimeout(r, 500)); changes.push('date'); } } if (newTime) { const timeInput = document.querySelector('input[aria-label*="Start time" i], input[aria-label*="time" i]'); if (timeInput) { const [h, min] = newTime.split(':'); const hrs = parseInt(h); const mins = parseInt(min) || 0; const ampm = hrs >= 12 ? 'PM' : 'AM'; const hr12 = hrs === 0 ? 12 : hrs > 12 ? hrs - 12 : hrs; const timeStr = hr12 + ':' + String(mins).padStart(2, '0') + ampm; timeInput.focus(); timeInput.click(); await new Promise(r => setTimeout(r, 300)); nativeSet.call(timeInput, timeStr); timeInput.dispatchEvent(new Event('input', { bubbles: true })); timeInput.dispatchEvent(new Event('change', { bubbles: true })); timeInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, bubbles: true })); await new Promise(r => setTimeout(r, 500)); changes.push('time'); } } if (changes.length === 0) return { error: 'No fields to update were provided or found' }; return { fields_updated: changes }`)

  // Brief pause before saving
  await browser.wait(1000)

  // Save the edited event
  const save_result = await browser.evaluate(`const saveBtn = document.querySelector('[aria-label="Save"], button[data-tooltip="Save"]'); if (!saveBtn) { const allButtons = [...document.querySelectorAll('button, [role="button"]')]; const save = allButtons.find(b => (b.textContent || '').trim().toLowerCase() === 'save'); if (save) { save.click(); } else { return { error: 'Could not find Save button' }; } } else { saveBtn.click(); } await new Promise(r => setTimeout(r, 3000)); return { success: true, event_title: params.event_title, new_title: params.new_title || undefined, new_date: params.new_date || undefined, new_time: params.new_time || undefined, url: window.location.href }`)

  return save_result
}
